+// ══ Dark Mode ══════════════════════════════════════════════════════════
+function toggleDark() {
+  state.darkMode = !state.darkMode;
+  localStorage.setItem("theme", state.darkMode ? "dark" : "light");
+  state.darkMode ? applyDark() : applyLight();
+}
+function applyDark() {
+  document.documentElement.setAttribute("data-theme","dark");
+  document.getElementById("theme-icon").className = "bi bi-sun";
+  updateChartsTheme();
+}
+function applyLight() {
+  document.documentElement.setAttribute("data-theme","light");
+  document.getElementById("theme-icon").className = "bi bi-moon-stars";
+  updateChartsTheme();
+}
+function updateChartsTheme() {
+  Object.values(state.charts).forEach(c => {
+    if (!c) return;
+    const gridColor = state.darkMode ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)";
+    const textColor = state.darkMode ? "#8b95b0" : "#6b7280";
+    if (c.options.scales) {
+      Object.values(c.options.scales).forEach(ax => {
+        if (ax.grid) ax.grid.color = gridColor;
+        if (ax.ticks) ax.ticks.color = textColor;
+      });
+    }
+    if (c.options.plugins?.legend?.labels) c.options.plugins.legend.labels.color = textColor;
+    c.update();
+  });
+}
