+// ══ Dashboard Stats ════════════════════════════════════════════════════
+async function loadDashboardStats() {
+  try {
+    const r = await fetch("/api/dataset-stats");
+    const d = await r.json();
+    if (d.error) return;
+    document.getElementById("stat-total").textContent = d.total_records.toLocaleString();
+    document.getElementById("stat-approval").textContent = d.approval_rate + "%";
