+  const rejected = d.total_records - approved;
+  state.charts["approvalPie"] = new Chart(ctx, {
+    type: "doughnut",
+    data: {
+      labels: ["Approved", "Rejected"],
+      datasets: [{ data: [approved, rejected], backgroundColor: ["#059669","#dc2626"], borderWidth: 0, hoverOffset: 6 }]
+    },
+    options: {
+      responsive: true, cutout: "65%",
+      plugins: {
+        legend: { position:"bottom", labels:{ color: state.darkMode?"#8b95b0":"#6b7280", font:{size:12} }},
+        tooltip: { callbacks:{ label: ctx => ` ${ctx.label}: ${ctx.raw} (${((ctx.raw/d.total_records)*100).toFixed(1)}%)` }}
+      }
+    }
+  });
+}
