+// ══ Prediction ═════════════════════════════════════════════════════════
+async function runPrediction(e) {
+  e.preventDefault();
+  const btn = document.getElementById("predict-btn");
+  btn.innerHTML = '<span class="spinner"></span> Analyzing…';
+  btn.disabled = true;
+
+  const fd = new FormData(e.target);
+  const payload = {};
+  fd.forEach((v, k) => { payload[k] = isNaN(v) ? v : Number(v); });
+
+  try {
+    const r = await fetch("/api/predict", {
+      method:"POST", headers:{"Content-Type":"application/json"},
+      body: JSON.stringify(payload)
+    });
+    const data = await r.json();
+    if (data.error) { showToast(data.error, "error"); return; }
+    state.lastPrediction = { prediction: data, applicant: payload };
+    renderResult(data);
+    showToast("Prediction complete!", "success");
+  } catch(err) {
+    showToast("Prediction failed. Is the server running?", "error");
+  } finally {
+    btn.innerHTML = '<i class="bi bi-lightning-charge"></i> Predict Eligibility';
+    btn.disabled = false;
+  }
+}
+
+function renderResult(data) {
+  document.getElementById("result-placeholder").style.display = "none";
+  const panel = document.getElementById("result-panel");
+  panel.classList.add("visible");
+
+  const hdr = document.getElementById("result-header");
+  hdr.className = "result-header " + (data.approved ? "result-approved" : "result-rejected");
+  document.getElementById("result-icon").textContent = data.approved ? "✅" : "❌";
+  document.getElementById("result-verdict").textContent = data.approved ? "Loan Approved" : "Loan Not Approved";
+  document.getElementById("result-sub").textContent =
+    `${data.confidence}% confidence  •  ${data.approved ? data.approval_probability : data.rejection_probability}% probability`;
+
+  // Confidence bar
+  setTimeout(() => {
+    document.getElementById("conf-fill").style.width = data.approval_probability + "%";
+    document.getElementById("conf-pct").textContent = data.approval_probability + "%";
+  }, 100);
+
+  document.getElementById("res-dti").textContent = data.dti_ratio + "%";
+  document.getElementById("res-emi").textContent = "₹" + data.monthly_emi.toLocaleString();
+  document.getElementById("res-income").textContent = "₹" + data.total_income.toLocaleString();
+
+  // Feature impact bars
+  const grid = document.getElementById("factors-grid");
+  grid.innerHTML = "";
+  data.feature_impact.forEach(f => {
+    const item = document.createElement("div");
+    item.className = "factor-item";
+    item.innerHTML = `
+      <div class="factor-name">${f.feature}</div>
+      <div class="factor-bar-track">
+        <div class="factor-bar-fill" style="width:0%" data-w="${f.importance}"></div>
+      </div>
+      <div class="factor-pct">${f.importance}%</div>`;
+    grid.appendChild(item);
+  });
+  setTimeout(() => {
+    grid.querySelectorAll(".factor-bar-fill").forEach(el => {
+      el.style.width = el.dataset.w + "%";
+    });
+  }, 150);
+}
+
+function resetForm() {
+  document.getElementById("predict-form").reset();
+  document.getElementById("result-panel").classList.remove("visible");
+  document.getElementById("result-placeholder").style.display = "";
+  state.lastPrediction = null;
+}
