+// ══ AI Chat ═════════════════════════════════════════════════════════════
+function addChatMessage(role, text, time) {
+  const container = document.getElementById("chat-messages");
+  const wrap = document.createElement("div");
+  wrap.className = "msg-wrap " + role;
+
+  const avatar = document.createElement("div");
+  avatar.className = "msg-avatar " + (role === "ai" ? "ai-avatar" : "user-avatar");
+  avatar.innerHTML = role === "ai" ? '<i class="bi bi-robot"></i>' : '<i class="bi bi-person"></i>';
+
+  const inner = document.createElement("div");
+  const bubble = document.createElement("div");
+  bubble.className = "msg-bubble " + (role === "ai" ? "ai-bubble" : "user-bubble");
+  bubble.textContent = text.replace(/\*\*(.*?)\*\*/g, "$1"); // strip markdown bold for plain text
+  bubble.innerHTML = formatMarkdown(text);
+
+  const ts = document.createElement("div");
+  ts.className = "msg-time";
+  ts.textContent = time || new Date().toLocaleTimeString([], {hour:"2-digit",minute:"2-digit"});
+
+  inner.appendChild(bubble);
+  inner.appendChild(ts);
+  wrap.appendChild(avatar);
+  wrap.appendChild(inner);
+  container.appendChild(wrap);
+  container.scrollTop = container.scrollHeight;
+}
+
+function formatMarkdown(text) {
+  return text
+    .replace(/\*\*(.*?)\*\*/g, "<strong>$1</strong>")
+    .replace(/•\s/g, "• ")
+    .replace(/\n/g, "<br>");
+}
