+  wrap.className = "msg-wrap ai"; wrap.id = "typing-msg";
+  wrap.innerHTML = `
+    <div class="msg-avatar ai-avatar"><i class="bi bi-robot"></i></div>
+    <div class="msg-bubble ai-bubble">
+      <div class="typing-indicator">
+        <div class="typing-dot"></div><div class="typing-dot"></div><div class="typing-dot"></div>
+      </div>
+    </div>`;
+  container.appendChild(wrap);
+  container.scrollTop = container.scrollHeight;
+}
+function removeTyping() {
+  const el = document.getElementById("typing-msg");
+  if (el) el.remove();
+}
+
+async function sendMessage() {
+  const input = document.getElementById("chat-input");
+  const text = input.value.trim();
+  if (!text) return;
+  input.value = ""; autoResize(input);
+
+  addChatMessage("user", text);
+  state.chatHistory.push({ role:"user", content:text });
+  showTyping();
+
+  try {
+    const r = await fetch("/api/chat", {
+      method:"POST", headers:{"Content-Type":"application/json"},
+      body: JSON.stringify({
+        message: text,
+        loan_context: state.lastPrediction,
+        history: state.chatHistory.slice(-6)
+      })
+    });
+    const d = await r.json();
+    removeTyping();
+    const reply = d.response || "Sorry, I couldn't process that.";
+    addChatMessage("ai", reply, d.timestamp);
+    state.chatHistory.push({ role:"assistant", content:reply });
+  } catch(err) {
+    removeTyping();
+    addChatMessage("ai", "Connection error. Please ensure the Flask server is running.");
+  }
+}
+
+function handleChatKey(e) {
+  if (e.key === "Enter" && !e.shiftKey) { e.preventDefault(); sendMessage(); }
+}
+function sendChip(el) { document.getElementById("chat-input").value = el.textContent; sendMessage(); }
+function clearChat() {
+  document.getElementById("chat-messages").innerHTML = "";
+  state.chatHistory = [];
+  addChatMessage("ai","Chat cleared. How can I help you?");
+}
+function autoResize(el) {
+  el.style.height = "auto";
+  el.style.height = Math.min(el.scrollHeight, 120) + "px";
+}
+function askAIAboutResult() {
+  showPage("chat", document.querySelectorAll(".nav-item")[2]);
+  document.getElementById("chat-input").value = "Explain my loan prediction result and what factors affected it most.";
+  sendMessage();
+}
