+    if (d.error) return;
+    const grid = state.darkMode ? "rgba(255,255,255,0.08)" : "rgba(0,0,0,0.06)";
+    const ticks = state.darkMode ? "#8b95b0" : "#6b7280";
+    const opts = (title) => ({
+      responsive:true,
+      plugins:{ legend:{ labels:{color:ticks,font:{size:12}} }, title:{display:false} },
+      scales:{ x:{grid:{color:grid},ticks:{color:ticks}}, y:{grid:{color:grid},ticks:{color:ticks}} }
+    });
+
+    if (!state.charts["edu"]) {
+      state.charts["edu"] = new Chart(document.getElementById("eduChart"), {
+        type:"bar",
+        data:{
+          labels: Object.keys(d.education_dist),
+          datasets:[{ label:"Count", data:Object.values(d.education_dist),
+            backgroundColor:["#3b82f6","#8b5cf6"], borderRadius:8, borderSkipped:false }]
